// Notificar error via Evolution API
const EVOLUTION_URL      = 'https://evolution.sekaitech.com.pe';
const EVOLUTION_API_KEY  = '6mF28RqtJdPIZorVIbAaRBiKZoZr3a5t4d9jikNna7c=';
const EVOLUTION_INSTANCE = 'sekaitech';
const GROUP_JID          = '120363423813951789@g.us';

const inp = $input.item.json;
const errorMsg = inp.message || inp.error || 'Error desconocido';
const ahora = new Date().toLocaleString('es-PE', { timeZone: 'America/Lima' });

const lines = [];
lines.push('\u26a0\ufe0f *ERROR \u2014 CEAM Auditor Scraper (Fichas)*');
lines.push('\ud83d\uddd3\ufe0f ' + ahora);
lines.push('\u2500'.repeat(34));
lines.push('El proceso de extraccion de catalogo fallo.');
lines.push('');
lines.push('Error: ' + errorMsg);
lines.push('');
lines.push('Revisa los logs en el contenedor del backend.');
const texto = lines.join('\n');

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: EVOLUTION_URL + '/message/sendText/' + EVOLUTION_INSTANCE,
    headers: { 'apikey': EVOLUTION_API_KEY, 'Content-Type': 'application/json' },
    body: { number: GROUP_JID, text: texto },
    json: true,
    timeout: 10000
  });
} catch(e) {}

return [{ json: { notified: true, error: String(errorMsg) } }];

// Construir mensajes agrupados por marca
const data = $input.first().json;

// El endpoint sincrono devuelve: { hayAlertas, total_suspendidas, datos, resumen }
const hayAlertas = data.hayAlertas;
const datos = data.datos || {};
const resumen = data.resumen || {};
const marcas = Object.keys(datos);

if (!hayAlertas || marcas.length === 0) {
  return [{ json: { hayAlertas: 'false', mensajes: [], total: 0 } }];
}

const sep = '\u2500'.repeat(30);
let totalSuspendidas = data.total_suspendidas || 0;

const partes = [];
partes.push('\u26a0\ufe0f *ALERTAS DE CATALOGO: FICHAS SUSPENDIDAS*');
partes.push('\ud83d\uddd3\ufe0f ' + new Date().toLocaleString('es-PE', { timeZone: 'America/Lima' }));
partes.push(sep);
partes.push('\ud83d\udea8 El escaner detecto ' + totalSuspendidas + ' ficha(s) suspendida(s):');

for (const marca of marcas) {
  const fichas = datos[marca];
  let infoResumen = '';
  if (resumen[marca] && resumen[marca].ofertadas_actuales !== undefined) {
    infoResumen = ' (Quedan ' + resumen[marca].ofertadas_actuales + ' ofertadas)';
  }
  partes.push('\n\ud83c\udfec *MARCA: ' + marca + '*' + infoResumen);
  fichas.forEach(function(f, i) {
    partes.push('   \u274c *' + (i + 1) + '.* P/N: *' + f.nro_parte + '*');
    if (f.descripcion) partes.push('      \u21b3 ' + f.descripcion);
  });
}

partes.push('\n' + sep);
partes.push('\ud83e\udd16 _CEAM Auditor Automatico_');

return [{ json: { hayAlertas: 'true', mensajes: [partes.join('\n')], total: totalSuspendidas } }];

// ENVIAR VIA EVOLUTION API -> GRUPO WHATSAPP CEAM
const EVOLUTION_URL      = 'https://evolution.sekaitech.com.pe';
const EVOLUTION_API_KEY  = '6mF28RqtJdPIZorVIbAaRBiKZoZr3a5t4d9jikNna7c=';
const EVOLUTION_INSTANCE = 'sekaitech';
const GROUP_JID          = '120363423813951789@g.us';

let results = [];

for (const item of $input.all()) {
  const mensaje = item.json.mensaje || '';
  if (!mensaje) continue;

  try {
    const r = await this.helpers.httpRequest({
      method: 'POST',
      url: EVOLUTION_URL + '/message/sendText/' + EVOLUTION_INSTANCE,
      headers: { 'apikey': EVOLUTION_API_KEY, 'Content-Type': 'application/json' },
      body: { number: GROUP_JID, text: mensaje },
      json: true,
      timeout: 15000
    });
    results.push({ json: { success: true, key: r.key } });
    await new Promise(resolve => setTimeout(resolve, 1500));
  } catch(e) {
    results.push({ json: { success: false, error: e.message } });
  }
}

return results;
